    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        //     {
        //         "TransactionId": 2663709493,
        //         "ReferenceId": 68,
        //         "OMSId": 1,
        //         "AccountId": 449,
        //         "CR": 10.000000000000000000000000000,
        //         "DR": 0.0000000000000000000000000000,
        //         "Counterparty": 3,
        //         "TransactionType": "Other",
        //         "ReferenceType": "Deposit",
        //         "ProductId": 1,
        //         "Balance": 10.000000000000000000000000000,
        //         "TimeStamp": 1607532331591
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(item, "ProductId");
        currency = this.safeCurrency(currencyId, currency);
        Object credit = this.safeString(item, "CR");
        Object debit = this.safeString(item, "DR");
        Object amount = null;
        Object direction = null;
        if (Helpers.isTrue(Precise.stringLt(credit, "0")))
        {
            amount = credit;
            direction = "in";
        } else if (Helpers.isTrue(Precise.stringLt(debit, "0")))
        {
            amount = debit;
            direction = "out";
        }
        Object before = null;
        Object after = this.safeString(item, "Balance");
        if (Helpers.isTrue(Helpers.isEqual(direction, "out")))
        {
            before = Precise.stringAdd(after, amount);
        } else if (Helpers.isTrue(Helpers.isEqual(direction, "in")))
        {
            before = Precise.stringMax("0", Precise.stringSub(after, amount));
        }
        Object timestamp = this.safeInteger(item, "TimeStamp");
        final Object finalDirection = direction;
        final Object finalCurrency = currency;
        final Object finalAmount = amount;
        final Object finalBefore = before;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", NdaxCore.this.safeString(item, "TransactionId") );
            put( "direction", finalDirection );
            put( "account", NdaxCore.this.safeString(item, "AccountId") );
            put( "referenceId", NdaxCore.this.safeString(item, "ReferenceId") );
            put( "referenceAccount", NdaxCore.this.safeString(item, "Counterparty") );
            put( "type", NdaxCore.this.parseLedgerEntryType(NdaxCore.this.safeString(item, "ReferenceType")) );
            put( "currency", NdaxCore.this.safeCurrencyCode(currencyId, finalCurrency) );
            put( "amount", NdaxCore.this.parseNumber(finalAmount) );
            put( "before", NdaxCore.this.parseNumber(finalBefore) );
            put( "after", NdaxCore.this.parseNumber(after) );
            put( "status", "ok" );
            put( "timestamp", timestamp );
            put( "datetime", NdaxCore.this.iso8601(timestamp) );
            put( "fee", null );
        }}, currency);
    }

